VALUES
  ('judicial-0b5ab5d8-moex-00106', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '關於審計權之行使，下列敘述何者錯誤？', '["監察院設審計長，由總統提名，經立法院同意任命之", "審計長應於行政院提出決算後3個月內，依法完成其審核", "審計長完成決算審核後，應提出審核報告於立法院", "地方之審計權屬於地方立法並執行之事項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00107', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '有關公務員懲戒，下列敘述何者正確？', '["法官之懲戒，亦包括大法官", "公務員懲戒法之適用對象，包括文職及武職之公務員、公立學校教師", "公務員懲戒案件之審理，為一級一審制", "司法院大法官之懲戒，得經司法院大法官現有總額3分之2以上之出席及出席人數3分之2以上之決 議，由司法院移送懲戒法院審理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00108', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '司法院釋字第472號解釋宣示，針對無力繳納全民健康保險費者，國家應給予適當救助，不得逕行拒絕給 付，此為何種基本權？', '["生存權", "財產權", "人身自由", "一般行為自由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00109', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '下列關於世界主要法系的敘述，何者錯誤？', '["羅馬日耳曼法系又常被稱作歐陸法系，重視成文法", "歐陸法系重視公法與私法的分類", "普通法系發源於美國", "普通法系以判決先例為主要法源，並特別重視程序法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00110', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '下列關於臺灣民商法發展之敘述，何者錯誤？', '["日治時期臺灣人的親屬繼承事項之實體法，原則上乃依照日本民法典", "戰前的日本民法典與戰後施行在臺灣的中華民國民法典，均以歐陸法為範本。是以戰前與戰後的臺灣民 事法之實質內容有許多延續之處", "1985年民法親屬繼承編首度修正，參考歐陸立法例朝向更平等的夫妻財產制", "戰後民商法的特色之一，為對於英美法，特別是美國法的繼受"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00111', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '有關地方政府得透過自治規章訂定行政罰則之規定，下列敘述何者錯誤？', '["直轄市法規、縣（市）規章就違反地方自治事項之行政業務者，得規定處以罰鍰或其他種類之行政罰", "直轄市政府、縣（市）政府得透過自治規則訂定罰鍰或其他種類之行政罰，惟需函送各該地方立法機關查照", "自治條例經各該地方立法機關決議後，如規定有罰則時，應分別報經行政院、中央各該主管機關核定後發布", "地方政府為罰鍰之規定，最高以新臺幣10萬元為限；逾期不繳納者，得依相關法律移送強制執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00112', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '依中央法規標準法規定，關於行政命令，下列敘述何者正確？', '["關於國家各機關組織規範得由行政命令訂之", "行政命令之原發布機關已裁併者，其廢止則由承受其業務之機關或其上級機關為之", "行政命令定有施行期限而主管機關認為需要延長者，須於期限屆滿日前發布延長即可", "各機關依其法定職權所制定之行政命令得自行發布，無須送交立法院"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00113', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '司法院釋字第792號解釋：毒品危害防制條例第4條「第1項至第4項將販賣毒品與製造、運輸毒品之構成要 件併列，並對該三種犯罪態樣，科以相同之法定刑。由此推論，本條所指之『販賣』毒品行為嚴重程度，應與製 造及運輸毒品相當。所謂製造毒品係將毒品從無至有，予以生產，進而得危害他人；而運輸毒品係從一地運至他 地，使毒品流通於他地，產生危害。基於同一法理，販賣毒品罪，應在處罰『賣出』毒品，因而產生毒品危害之 行為，蓋販賣須如此解釋，其嚴重程度始與上述製造與運輸毒品之危害相當。」是屬於下列何種解釋方法？', '["文義解釋", "歷史解釋", "體系解釋", "目的解釋"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00114', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '有關授權明確性原則之敘述，下列何者錯誤？', '["立法機關授權行政機關發布命令，為憲法所許，只要其授權目的、內容或範圍其中之一具體明確即可", "在此原則之下，授權條款之明確程度，應與所授權訂定之法規命令對人民權利之影響相稱", "由授權之母法整體觀察，已足使人民預見行為有受處罰之可能，即與得預見行為可罰之意旨無違，不以 確信其行為之可罰為必要", "此乃法律保留原則之補充與具體化"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00115', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '依據司法院大法官解釋，下列何者無須由法律明文規定？', '["消滅時效", "課徵租稅之構成要件", "公務員懲戒撤職處分之構成要件", "公務人員專案考績一次記二大過免職之構成要件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL)
